class Solution {
public:
    int scheduleSubintervals(vector<vector<int>>& intervals, int T) {
        sort(intervals.begin(), intervals.end(), [](vector<int>& a, vector<int>& b) {
            return a[1] < b[1];
        });
        int count = 1;
        for (int i = 1; i < intervals.size(); i++) {
            if (intervals[i][0] > intervals[i-1][1] + 1) {
                count++;
            }
        }
        return count;
    }
};
